#:property AllowUnsafeBlocks=true

Span<nint> nints = stackalloc nint[5];
for (int i = 0; i < nints.Length; i++)
    nints[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {nints.Length}, sizeof(nint): {sizeof(nint)}");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  nints[{i}] = {nints[i]}");

Span<nuint> nuints = stackalloc nuint[3];
nuints[0] = 42;
nuints[1] = nuint.MaxValue;
nuints[2] = 0;

Console.WriteLine($"\nSpan<nuint> length: {nuints.Length}, sizeof(nuint): {sizeof(nuint)}");
for (int i = 0; i < nuints.Length; i++)
    Console.WriteLine($"  nuints[{i}] = {nuints[i]}");

